('riz_et_pois_rouges_guadeloupean', 'Riz et pois rouges', 165, 5.5, 30.2, 2.1, 3.2, 0.4, 200, NULL, 'research', ARRAY['riz et pois rouges', 'riz aux pois', 'rice and peas antillais'], 'traditional', NULL, 1, 'GP', 'Guadeloupe''s most iconic side dish — white rice cooked with red kidney beans and coconut milk. Served alongside virtually every traditional meal.', TRUE),
('igname_bouilli_guadeloupean', 'Igname bouilli', 118, 1.5, 27.9, 0.2, 4.1, 0.5, 200, NULL, 'research', ARRAY['igname bouilli', 'igname cuite', 'yam bouilli'], 'root_vegetable', NULL, 1, 'GP', 'Boiled white yam is a cornerstone starch in Guadeloupe, consumed daily as a substitute for rice or alongside meat dishes. Several local varieties exist.', TRUE),
('dachine_au_lait_de_coco_guadeloupean', 'Dachine au lait de coco', 142, 2.0, 26.5, 3.8, 2.9, 1.2, 200, NULL, 'research', ARRAY['dachine au lait de coco', 'taro coco', 'dachine coco'], 'root_vegetable', NULL, 1, 'GP', 'Taro cooked in coconut milk is a beloved Guadeloupean preparation that transforms the starchy root into a creamy, subtly sweet dish.', TRUE),
('giraumon_en_gratin_guadeloupean', 'Giraumon en gratin', 98, 3.8, 12.4, 4.2, 1.8, 3.5, 200, NULL, 'research', ARRAY['giraumon en gratin', 'gratin giraumon', 'pumpkin gratin créole'], 'traditional', NULL, 1, 'GP', 'Calabaza pumpkin baked au gratin with local cheese and béchamel. Giraumon is the quintessential Caribbean squash and appears in countless Guadeloupean recipes.', TRUE),
('christophine_farcie_guadeloupean', 'Christophine farcie', 112, 5.2, 9.8, 5.5, 2.1, 2.3, 200, NULL, 'research', ARRAY['christophine farcie', 'chayote farcie', 'cho-cho farci'], 'traditional', NULL, 1, 'GP', 'Chayote stuffed with seasoned meat or salt cod mixture, then baked — a classic Guadeloupean Sunday lunch preparation.', TRUE),
('fruit_a_pain_en_beignet_guadeloupean', 'Fruit à pain en beignet', 198, 2.1, 32.5, 7.8, 2.4, 3.1, 100, 80, 'research', ARRAY['fruit à pain en beignet', 'beignet d''arbre à pain', 'breadfruit fritter'], 'traditional', NULL, 1, 'GP', 'Breadfruit fritters are a popular street food in Guadeloupe — slices of ripe breadfruit dipped in seasoned batter and deep-fried until golden.', TRUE),
('plantain_mur_au_four_guadeloupean', 'Plantain mûr au four', 122, 1.3, 31.9, 0.4, 2.3, 15.2, 150, NULL, 'research', ARRAY['plantain mûr au four', 'banane plantain rôtie', 'plantain baked'], 'staple', NULL, 1, 'GP', 'Ripe plantain baked whole in the skin until caramelized — a simple, naturally sweet preparation common at breakfast and as a dessert accompaniment.', TRUE),
('manioc_frit_guadeloupean', 'Manioc frit', 219, 1.0, 36.8, 7.9, 1.8, 1.5, 150, NULL, 'research', ARRAY['manioc frit', 'cassave frite', 'yuca frito antillais'], 'root_vegetable', NULL, 1, 'GP', 'Fried cassava sticks are a popular street food and snack throughout Guadeloupe, often sold at markets alongside salt fish and grilled meats.', TRUE),
('couac_au_bouillon_guadeloupean', 'Couac au bouillon', 155, 3.2, 34.1, 0.6, 1.2, 0.3, 150, NULL, 'research', ARRAY['couac au bouillon', 'kwak', 'farine de manioc grillée'], 'traditional', NULL, 1, 'GP', 'Coarse cassava meal (couac) cooked with broth — a traditional Amerindian-descended staple that remains an everyday grain in Guadeloupe and French Guiana.', TRUE),
('pois_dangole_au_riz_guadeloupean', 'Pois d''angole au riz', 170, 6.8, 31.5, 1.8, 5.2, 1.0, 200, NULL, 'research', ARRAY['pois d''angole au riz', 'riz pois d''angole', 'pois congo au riz'], 'legume', NULL, 1, 'GP', 'Pigeon peas slow-cooked with rice, herbs, and salt meat is a staple one-pot dish throughout Guadeloupe. Pois d''angole grow abundantly on the island.', TRUE),
('lentilles_creoles_mijotees_guadeloupean', 'Lentilles créoles mijotées', 116, 9.0, 20.1, 0.4, 7.9, 1.8, 200, NULL, 'research', ARRAY['lentilles créoles mijotées', 'lentilles en sauce créole', 'lentilles antillaises'], 'legume', NULL, 1, 'GP', 'Small green lentils simmered with thyme, garlic, and local spices. Creole-style lentils are a weekday staple often served over rice in Guadeloupe.', TRUE),
('feroce_davocat_a_la_morue_guadeloupean', 'Féroce d''avocat à la morue', 195, 8.2, 12.5, 13.1, 5.8, 0.8, 150, NULL, 'research', ARRAY['féroce d''avocat à la morue', 'féroce morue', 'avocat morue féroce'], 'traditional', NULL, 1, 'GP', 'Guadeloupe''s signature appetizer — ripe avocado mashed with shredded salt cod, cassava flour (couac), hot pepper, and lime. The name means ''ferocious'' for its heat.', TRUE),
('riz_creole_blanc_guadeloupean', 'Riz créole blanc', 130, 2.7, 28.6, 0.3, 0.4, 0.0, 200, NULL, 'research', ARRAY['riz créole blanc', 'riz cuit à l''eau', 'riz vapeur créole'], 'staple', NULL, 1, 'GP', 'Plain steamed white rice cooked the Creole way — rinsed thoroughly and cooked by absorption with a bay leaf. The neutral base for nearly all Guadeloupean meals.', TRUE),
('haricots_rouges_mijotes_guadeloupean', 'Haricots rouges mijotés', 127, 8.7, 22.8, 0.5, 7.4, 0.3, 200, NULL, 'research', ARRAY['haricots rouges mijotés', 'pois rouges à la créole', 'red beans créole'], 'legume', NULL, 1, 'GP', 'Red kidney beans slow-simmered with smoked pork, garlic, thyme, and local herbs. A fundamental protein and fiber source in the Guadeloupean diet.', TRUE),
('patate_douce_bouillie_guadeloupean', 'Patate douce bouillie', 86, 1.6, 20.1, 0.1, 3.0, 4.2, 200, NULL, 'research', ARRAY['patate douce bouillie', 'sweet potato bouilli', 'patate créole bouillie'], 'root_vegetable', NULL, 1, 'GP', 'Boiled sweet potato is an everyday starch in Guadeloupe, served as a side alongside fish or meat. The local orange-fleshed variety is particularly prized.', TRUE),
