('pois_chiches_en_sauce_creole_guadeloupean', 'Pois chiches en sauce créole', 164, 8.9, 27.4, 2.7, 7.6, 4.8, 200, NULL, 'research', ARRAY['pois chiches en sauce créole', 'pois chiche créole', 'chickpeas antillais'], 'legume', NULL, 1, 'GP', 'Chickpeas braised in Creole tomato sauce with allspice and scotch bonnet. Though less traditional than red beans, chickpeas have a strong presence in modern Guadeloupean cooking.', TRUE),
('pois_casses_au_porc_guadeloupean', 'Pois cassés au porc', 148, 10.2, 23.5, 2.8, 8.1, 2.1, 200, NULL, 'research', ARRAY['pois cassés au porc', 'soupe pois cassés', 'split peas créole'], 'legume', NULL, 1, 'GP', 'Yellow split peas cooked with smoked pork, herbs, and local spices into a thick, hearty stew. A budget-friendly staple that stretches across generations of Guadeloupean households.', TRUE),
