('igname_en_robe_des_champs_guadeloupean', 'Igname en robe des champs', 118, 1.5, 27.9, 0.2, 4.1, 0.5, 200, NULL, 'research', ARRAY['igname en robe des champs', 'igname bouillie', 'yam in skin'], 'traditional', NULL, 1, 'GP', 'Jacket-cooked tropical yam (igname), a major starchy staple in Guadeloupe with West African roots. Several varieties exist including igname blanc and igname jaune.', TRUE),
('dachine_sautee_guadeloupean', 'Dachine sautée', 124, 1.7, 28.0, 1.8, 4.1, 0.5, 150, NULL, 'research', ARRAY['dachine sautée', 'taro sauté', 'chou caraïbe sauté'], 'traditional', NULL, 1, 'GP', 'Sautéed taro root (dachine) with butter and herbs. Dachine is the local name for taro in Guadeloupe and is an important carbohydrate source in traditional Creole cuisine.', TRUE),
('feuilles_de_dachine_mijotees_guadeloupean', 'Feuilles de dachine mijotées', 52, 5.5, 8.9, 0.9, 2.8, 1.2, 120, NULL, 'research', ARRAY['feuilles de dachine mijotées', 'calalou aux feuilles de dachine', 'taro leaves stew'], 'traditional', NULL, 1, 'GP', 'Stewed taro leaves (called calalou or dachine leaves) slowly cooked with okra and salt meat. A dish of West African origin that became foundational in Guadeloupe''s Creole kitchen.', TRUE),
('giraumon_roti_guadeloupean', 'Giraumon rôti', 32, 1.0, 7.5, 0.5, 0.8, 3.2, 150, NULL, 'research', ARRAY['giraumon rôti', 'potiron rôti', 'giromon au four'], 'traditional', NULL, 1, 'GP', 'Roasted Caribbean pumpkin (giraumon), a turban-shaped squash variety native to the Americas. Used throughout Guadeloupe in soups, sides, and stews.', TRUE),
('puree_de_giraumon_guadeloupean', 'Purée de giraumon', 38, 1.2, 8.5, 0.8, 0.7, 3.5, 180, NULL, 'research', ARRAY['purée de giraumon', 'purée de potiron créole', 'giraumon en purée'], 'traditional', NULL, 1, 'GP', 'Smooth purée of Caribbean pumpkin with butter and nutmeg, a classic Guadeloupean side dish served alongside fish and meats. Giraumon has a richer sweetness than standard pumpkin.', TRUE),
('gombo_saute_a_lail_guadeloupean', 'Gombo sauté à l''ail', 38, 2.0, 8.2, 0.8, 3.2, 1.7, 120, NULL, 'research', ARRAY['gombo sauté à l''ail', 'okra sauté', 'gombo à l''ail'], 'traditional', NULL, 1, 'GP', 'Okra sautéed with garlic and local piment végétarien, known as gombo in Guadeloupe. Brought from West Africa during the colonial period, it remains a common side dish.', TRUE),
('aubergine_a_la_creole_guadeloupean', 'Aubergine à la créole', 48, 1.2, 6.5, 2.5, 3.0, 3.8, 150, NULL, 'research', ARRAY['aubergine à la créole', 'bélangère à la créole', 'aubergine créole'], 'traditional', NULL, 1, 'GP', 'Eggplant cooked Creole style with tomatoes, onions, thyme, and local spices. Guadeloupeans use both globe and small local varieties in this fragrant side dish.', TRUE),
('salade_de_christophine_rapee_guadeloupean', 'Salade de christophine râpée', 28, 0.7, 5.8, 1.5, 1.5, 2.2, 120, NULL, 'research', ARRAY['salade de christophine râpée', 'salade christophine crue', 'chayote salad'], 'traditional', NULL, 1, 'GP', 'Raw grated christophine salad dressed with lime juice, vinegar, and herbs. A refreshing and crunchy salad popular in Guadeloupe especially during hot weather.', TRUE),
('salade_de_concombre_creole_guadeloupean', 'Salade de concombre créole', 18, 0.7, 3.5, 0.5, 0.8, 2.0, 150, NULL, 'research', ARRAY['salade de concombre créole', 'salade concombre antillaise', 'concombre vinaigretté'], 'traditional', NULL, 1, 'GP', 'Cucumber salad with vinegar, local piment, garlic, and parsley. A ubiquitous side salad in Guadeloupean homes, served to temper the heat of spicy main dishes.', TRUE),
('salade_de_tomates_creole_guadeloupean', 'Salade de tomates créole', 24, 1.0, 4.5, 0.8, 1.2, 3.0, 150, NULL, 'research', ARRAY['salade de tomates créole', 'salade tomate antillaise', 'tomates en vinaigrette'], 'traditional', NULL, 1, 'GP', 'Sliced tomatoes with red onion, cives (local chives), vinegar and oil dressing. A simple but essential salad served alongside nearly every Guadeloupean main course.', TRUE),
('salade_de_palmiste_guadeloupean', 'Salade de palmiste', 36, 2.5, 5.0, 1.2, 2.2, 2.0, 120, NULL, 'research', ARRAY['salade de palmiste', 'salade coeur de palmier', 'chou palmiste en salade'], 'traditional', NULL, 1, 'GP', 'Heart of palm salad dressed with lime vinaigrette. Palm hearts are harvested from local acoma palms and prized as a delicacy in Guadeloupean cuisine, often called ''millionnaire''s salad''.', TRUE),
('salade_davocat_creole_guadeloupean', 'Salade d''avocat créole', 142, 2.0, 5.5, 13.0, 5.0, 0.8, 120, NULL, 'research', ARRAY['salade d''avocat créole', 'zaboca en salade', 'salade avocat antillaise'], 'traditional', NULL, 1, 'GP', 'Avocado salad with citrus dressing, red onion, and piment végétarien. Guadeloupe grows large local varieties of avocado (known as zaboca) that are creamier than Hass.', TRUE),
('salade_de_pois_dangole_guadeloupean', 'Salade de pois d''Angole', 110, 5.4, 14.2, 1.0, 4.8, 1.5, 150, NULL, 'research', ARRAY['salade de pois d''angole', 'salade pois congo', 'pigeon pea salad'], 'traditional', NULL, 1, 'GP', 'Pigeon pea salad with onion, herbs, and vinaigrette. Pois d''Angole (pigeon peas) were brought from Africa during slavery and are now integral to Guadeloupean cooking.', TRUE),
('salade_de_lentilles_creole_guadeloupean', 'Salade de lentilles créole', 116, 9.0, 20.1, 0.4, 7.9, 1.8, 150, NULL, 'research', ARRAY['salade de lentilles créole', 'salade lentilles antillaise', 'lentilles en salade'], 'traditional', NULL, 1, 'GP', 'Cooked lentil salad with scallions, thyme, and lime dressing. Although lentils arrived with French colonial influence, Guadeloupeans developed their own Creole seasoning approach.', TRUE),
('salade_de_haricots_rouges_guadeloupean', 'Salade de haricots rouges', 127, 8.7, 22.8, 0.5, 6.4, 0.3, 150, NULL, 'research', ARRAY['salade de haricots rouges', 'salade haricots rouges antillaise', 'red bean salad'], 'traditional', NULL, 1, 'GP', 'Red kidney bean salad with parsley, onion, and vinaigrette. Haricots rouges are staples of Guadeloupean Creole cuisine, served both warm and cold as a side.', TRUE),
('salade_de_riz_creole_guadeloupean', 'Salade de riz créole', 148, 3.2, 30.5, 2.0, 0.6, 1.5, 200, NULL, 'research', ARRAY['salade de riz créole', 'riz en salade', 'salade composée au riz'], 'traditional', NULL, 1, 'GP', 'Cold rice salad with vegetables, herbs, and vinaigrette dressing. A popular Guadeloupean lunch dish adapted from French rice salad traditions with local spices and vegetables.', TRUE),
('salade_de_mais_creole_guadeloupean', 'Salade de maïs créole', 98, 3.2, 21.0, 1.2, 2.4, 4.5, 150, NULL, 'research', ARRAY['salade de maïs créole', 'salade de blé d''inde', 'corn salad antillaise'], 'traditional', NULL, 1, 'GP', 'Corn salad with tomato, cives, and creole vinaigrette. Fresh corn on the cob (maïs) is grilled and sold as street food throughout Guadeloupe''s markets.', TRUE),
('salade_de_papaye_verte_guadeloupean', 'Salade de papaye verte', 35, 0.6, 8.8, 0.1, 1.8, 5.2, 120, NULL, 'research', ARRAY['salade de papaye verte', 'salade papaye verte antillaise', 'green papaya slaw'], 'traditional', NULL, 1, 'GP', 'Green papaya salad with lime juice, chili, and herbs. This refreshing salad uses unripe papaya, which has Asian influences filtered through the Caribbean trading routes.', TRUE),
('salade_de_chou_creole_guadeloupean', 'Salade de chou créole', 30, 1.5, 5.8, 0.9, 2.2, 3.0, 150, NULL, 'research', ARRAY['salade de chou créole', 'chou en salade', 'coleslaw créole'], 'traditional', NULL, 1, 'GP', 'Shredded cabbage salad with carrot, vinegar, and local seasoning. A daily staple in Guadeloupean homes often paired with fried fish and rice.', TRUE),
('salade_de_carotte_rapee_epicee_guadeloupean', 'Salade de carotte râpée épicée', 45, 1.0, 10.5, 0.3, 2.8, 5.2, 120, NULL, 'research', ARRAY['salade de carotte râpée épicée', 'carottes râpées créoles', 'carrot salad antillaise'], 'traditional', NULL, 1, 'GP', 'Grated carrot salad seasoned with lime, cives, and piment végétarien. A vibrant and nutritious side dish found in Guadeloupean snack shops and homes.', TRUE),
('salade_de_betterave_creole_guadeloupean', 'Salade de betterave créole', 43, 1.6, 9.6, 0.2, 2.8, 6.8, 120, NULL, 'research', ARRAY['salade de betterave créole', 'betterave vinaigrette', 'beet salad antillaise'], 'traditional', NULL, 1, 'GP', 'Cooked beet salad with onion, vinegar, and parsley. Betterave is a popular French-influenced salad ingredient adopted by Guadeloupeans and dressed with creole vinaigrette.', TRUE),
('legumes_pays_sautes_guadeloupean', 'Légumes-pays sautés', 85, 2.5, 15.0, 2.2, 3.5, 2.0, 200, NULL, 'research', ARRAY['légumes-pays sautés', 'légumes créoles sautés', 'mixed root vegetable sauté'], 'traditional', NULL, 1, 'GP', 'Mixed sauté of local vegetables (''légumes pays'') including plantain, igname, dachine, and breadfruit. A hearty side dish reflecting the agricultural abundance of Guadeloupe.', TRUE),
('banane_plantain_bouillie_guadeloupean', 'Banane plantain bouillie', 116, 1.2, 28.5, 0.3, 2.3, 5.0, 150, NULL, 'research', ARRAY['banane plantain bouillie', 'plantain vert bouilli', 'banane verte à l''eau'], 'traditional', NULL, 1, 'GP', 'Boiled green plantain, a fundamental starchy side dish in Guadeloupe. Green plantain is eaten as a savory carbohydrate alongside meat and fish stews.', TRUE),
('banane_plantain_frite_guadeloupean', 'Banane plantain frite', 178, 1.3, 30.2, 6.5, 2.0, 8.0, 100, NULL, 'research', ARRAY['banane plantain frite', 'banane frite', 'plantain maduro frit'], 'traditional', NULL, 1, 'GP', 'Fried ripe plantain slices, golden and caramelized. Ripe plantain (banane mûre) is much sweeter than green and is eaten as a side dish or dessert across Guadeloupe.', TRUE),
('banane_verte_a_la_vapeur_guadeloupean', 'Banane verte à la vapeur', 109, 1.1, 27.0, 0.2, 2.1, 3.5, 150, NULL, 'research', ARRAY['banane verte à la vapeur', 'figue verte vapeur', 'green banana steamed'], 'traditional', NULL, 1, 'GP', 'Steamed green banana served as a starchy side dish. Green bananas (not plantain) are steamed in their skins in Guadeloupe and eaten with salt fish or meat stews.', TRUE),
('fruit_a_pain_bouilli_guadeloupean', 'Fruit à pain bouilli', 103, 1.1, 27.1, 0.2, 4.9, 11.0, 200, NULL, 'research', ARRAY['fruit à pain bouilli', 'arbre à pain bouilli', 'breadfruit boiled'], 'traditional', NULL, 1, 'GP', 'Boiled breadfruit (fruit à pain), a traditional starchy staple introduced to the Caribbean from Polynesia in the 18th century. In Guadeloupe it is eaten boiled, fried, or roasted.', TRUE),
('fruit_a_pain_roti_guadeloupean', 'Fruit à pain rôti', 120, 1.3, 30.5, 0.4, 4.5, 12.0, 200, NULL, 'research', ARRAY['fruit à pain rôti', 'fruit à pain au charbon', 'roasted breadfruit'], 'traditional', NULL, 1, 'GP', 'Roasted whole breadfruit placed directly over charcoal until the skin chars and the flesh becomes soft. A street food tradition across Guadeloupe''s markets and festivals.', TRUE),
('manioc_bouilli_guadeloupean', 'Manioc bouilli', 160, 1.4, 38.0, 0.3, 1.8, 1.7, 150, NULL, 'research', ARRAY['manioc bouilli', 'cassava bouillie', 'manioc à l''eau'], 'traditional', NULL, 1, 'GP', 'Boiled cassava (manioc), an ancient Amerindian staple that was the primary carbohydrate source for the indigenous Arawak people of Guadeloupe before European contact.', TRUE),
('galette_de_manioc_guadeloupean', 'Galette de manioc', 358, 1.8, 87.0, 0.5, 2.0, 0.5, 60, 60, 'research', ARRAY['galette de manioc', 'cassave', 'manioc flatbread', 'couac bread'], 'traditional', NULL, 1, 'GP', 'Flat cassava bread made from grated and pressed bitter manioc, then toasted on a griddle. This flatbread is of direct Amerindian origin and is one of the oldest foods in Guadeloupean history.', TRUE),
('couac_guadeloupean', 'Couac', 362, 2.0, 88.0, 0.4, 1.5, 0.3, 50, NULL, 'research', ARRAY['couac', 'farine de manioc grillée', 'cassava granules'], 'traditional', NULL, 1, 'GP', 'Toasted granulated cassava flour used as a side starch, similar to Brazilian farofa. Couac is of Amerindian origin and remains a traditional accompaniment to stews in Guadeloupe.', TRUE),
('pile_de_bananes_vertes_guadeloupean', 'Pilé de bananes vertes', 132, 1.4, 30.8, 1.8, 2.5, 4.0, 150, NULL, 'research', ARRAY['pilé de bananes vertes', 'banane pilée', 'mashed green plantain'], 'traditional', NULL, 1, 'GP', 'Pounded green plantain paste similar to Dominican mangú. In Guadeloupe this dish reflects African food traditions preserved since the era of slavery.', TRUE),
('mais_pele_guadeloupean', 'Maïs pèlé', 108, 3.5, 22.8, 1.5, 3.0, 4.2, 150, NULL, 'research', ARRAY['maïs pèlé', 'maïs au lait de coco', 'boiled corn kernels'], 'traditional', NULL, 1, 'GP', 'Whole kernel corn boiled with coconut milk and sugar. Maïs pèlé is a traditional Guadeloupean snack and side dish often sold at street markets and festivals.', TRUE),
('pois_chiche_saute_creole_guadeloupean', 'Pois chiche sauté créole', 164, 8.9, 27.4, 2.6, 7.6, 4.8, 150, NULL, 'research', ARRAY['pois chiche sauté créole', 'pois chiches créoles', 'channa antillais'], 'traditional', NULL, 1, 'GP', 'Chickpeas sautéed with local spices, garlic, and tomatoes. Chickpeas were introduced to Guadeloupe by Indian indentured workers who arrived after emancipation in 1848.', TRUE),
('pois_dangole_mijote_guadeloupean', 'Pois d''Angole mijoté', 110, 5.4, 20.5, 1.2, 5.0, 1.8, 180, NULL, 'research', ARRAY['pois d''angole mijoté', 'pois congo mijoté', 'pigeon peas stew'], 'traditional', NULL, 1, 'GP', 'Stewed pigeon peas with Creole seasoning, tomatoes, and local herbs. Called pois d''Angole or pois Congo, this African-origin legume is central to Guadeloupean cuisine.', TRUE),
('haricots_blancs_creoles_guadeloupean', 'Haricots blancs créoles', 139, 9.7, 25.1, 0.5, 6.3, 0.3, 180, NULL, 'research', ARRAY['haricots blancs créoles', 'haricots blancs à la créole', 'white beans stewed'], 'traditional', NULL, 1, 'GP', 'White beans cooked Creole style with tomato, garlic, and thyme. A hearty side dish with strong French influence, adapted with local spices in Guadeloupean family cooking.', TRUE),
('gratin_de_banane_plantain_guadeloupean', 'Gratin de banane plantain', 185, 4.5, 30.0, 6.0, 2.2, 9.5, 200, NULL, 'research', ARRAY['gratin de banane plantain', 'plantain au gratin', 'gratin de banane'], 'traditional', NULL, 1, 'GP', 'Baked plantain gratin layered with cheese and béchamel. A French-Creole fusion dish that merges the starchy plantain beloved in Guadeloupe with classic French gratin technique.', TRUE),
('legumes_en_sauce_tomate_creole_guadeloupean', 'Légumes en sauce tomate créole', 68, 2.8, 12.0, 1.8, 3.5, 5.0, 200, NULL, 'research', ARRAY['légumes en sauce tomate créole', 'ratatouille créole', 'légumes en sauce'], 'traditional', NULL, 1, 'GP', 'Mixed vegetables cooked in a rich Creole tomato sauce seasoned with cives, thyme, garlic, and piment végétarien. A flexible dish using whatever seasonal vegetables are available.', TRUE),
('breadfruit_chips_guadeloupean', 'Breadfruit chips', 355, 2.5, 80.0, 3.5, 8.0, 15.0, 30, NULL, 'research', ARRAY['breadfruit chips', 'chips de fruit à pain', 'breadfruit crisps'], 'traditional', NULL, 1, 'GP', 'Thin slices of breadfruit deep-fried until crispy, served as a snack or side. A popular street food innovation across Guadeloupe, capitalizing on the abundant breadfruit harvest.', TRUE),
('cives_sautees_guadeloupean', 'Cives sautées', 32, 1.8, 7.3, 0.2, 2.6, 2.3, 50, NULL, 'research', ARRAY['cives sautées', 'ciboulette antillaise sautée', 'spring onion sauté'], 'traditional', NULL, 1, 'GP', 'Sautéed cives (Caribbean chives / Allium fistulosum), an essential flavoring herb in Guadeloupean cuisine used both as a side and seasoning. Cives differ from European chives in their robustness.', TRUE),
('thym_pays_frit_guadeloupean', 'Thym pays frit', 101, 5.6, 24.5, 1.7, 14.0, 1.5, 20, NULL, 'research', ARRAY['thym pays frit', 'thym créole frit', 'local thyme fried'], 'traditional', NULL, 1, 'GP', 'Fried local thyme leaves, used as a garnish and snack in Guadeloupe. Thyme pays (local thyme) is a broader-leafed variety with stronger flavor than European thyme.', TRUE),
