('fougere_comestible_sautee_guadeloupean', 'Fougère comestible sautée', 34, 4.5, 5.8, 0.4, 2.0, 0.8, 100, NULL, 'research', ARRAY['fougère comestible sautée', 'chou fougère sauté', 'fern shoots sauté'], 'traditional', NULL, 1, 'GP', 'Sautéed edible fern fronds (chou fougère), gathered in the rainforest of Basse-Terre. This wild foraged green is a traditional mountain food of rural Guadeloupe.', TRUE),
('fleur_de_giraumon_fritte_guadeloupean', 'Fleur de giraumon fritte', 52, 1.8, 8.0, 2.0, 1.2, 1.5, 60, NULL, 'research', ARRAY['fleur de giraumon fritte', 'fleurs de courge frites', 'squash blossom fritter'], 'traditional', NULL, 1, 'GP', 'Fried pumpkin flowers battered in seasoned flour. Male flowers from giraumon plants are harvested and fried as a delicacy in traditional Guadeloupean rural cooking.', TRUE),
('salade_tiede_digname_guadeloupean', 'Salade tiède d''igname', 120, 1.6, 28.5, 0.8, 4.0, 0.8, 150, NULL, 'research', ARRAY['salade tiède d''igname', 'igname en salade tiède', 'warm yam salad'], 'traditional', NULL, 1, 'GP', 'Warm yam salad dressed with vinaigrette, herbs, and shallots. Igname (tropical yam) salads are served warm as a substantial side dish in Guadeloupean restaurants.', TRUE),
('epinards_creoles_sautes_guadeloupean', 'Épinards créoles sautés', 40, 3.5, 4.5, 1.8, 2.5, 0.5, 120, NULL, 'research', ARRAY['épinards créoles sautés', 'épinards à la créole', 'spinach sauté antillaise'], 'traditional', NULL, 1, 'GP', 'Sautéed spinach with garlic, chili, and local herbs. While spinach is a French-influenced vegetable, Guadeloupeans often substitute local leafy greens like brèdes or use spinach with Creole seasonings.', TRUE),
('bredes_mijote_guadeloupean', 'Brèdes mijoté', 38, 3.2, 5.8, 0.8, 2.8, 1.0, 120, NULL, 'research', ARRAY['brèdes mijoté', 'brèdes sautées', 'leafy greens stew créole'], 'traditional', NULL, 1, 'GP', 'Stewed leafy greens (brèdes), typically leaves of sweet potato or water spinach. Brèdes dishes are of African origin and remain a foundational element of the Guadeloupean diet.', TRUE),
('maracudja_en_salade_guadeloupean', 'Maracudja en salade', 42, 1.0, 10.0, 0.3, 4.5, 5.0, 80, NULL, 'research', ARRAY['maracudja en salade', 'fruits de la passion en salade', 'passion fruit salad dressing'], 'traditional', NULL, 1, 'GP', 'Passion fruit (maracudja) used as a dressing for fruit salads. Maracudja is widely grown in Guadeloupe and adds a distinctive tart flavor to salads and desserts.', TRUE),
('salade_de_cur_de_chou_palmiste_guadeloupean', 'Salade de cœur de chou palmiste', 41, 2.8, 7.5, 0.5, 3.2, 2.8, 100, NULL, 'research', ARRAY['salade de cœur de chou palmiste', 'palmito en salade', 'heart of palm salad'], 'traditional', NULL, 1, 'GP', 'Fresh heart of palm salad from locally harvested royal palms. A luxurious salad once reserved for wealthy plantation owners, now more widely available from cultivated palms.', TRUE),
('pain_au_beurre_guadeloupeen_guadeloupean', 'Pain au beurre guadeloupéen', 310, 7.5, 48.0, 9.5, 1.8, 6.0, 80, 80, 'research', ARRAY['pain au beurre guadeloupéen', 'pain beurré antillais', 'butter bread guadeloupe'], 'traditional', NULL, 1, 'GP', 'Soft enriched butter bread unique to Guadeloupe, a morning staple eaten with coffee or chocolate. This bread has been baked by local boulangeries for over a century with French technique.', TRUE),
('pain_doux_creole_guadeloupean', 'Pain doux créole', 285, 6.5, 52.0, 6.0, 1.5, 12.0, 80, 80, 'research', ARRAY['pain doux créole', 'pain sucré créole', 'sweet creole bread'], 'traditional', NULL, 1, 'GP', 'Sweet soft bread baked in traditional Guadeloupean boulangeries. Pain doux (sweet bread) is enriched with sugar and vanilla and enjoyed as a breakfast bread.', TRUE),
('pain_cocotier_guadeloupean', 'Pain cocotier', 298, 5.5, 48.5, 9.2, 2.5, 8.0, 80, 80, 'research', ARRAY['pain cocotier', 'pain au lait de coco', 'coconut bread créole'], 'traditional', NULL, 1, 'GP', 'Coconut bread made with grated fresh coconut incorporated into the dough. A cherished Guadeloupean breakfast bread sold in village boulangeries and at Sunday markets.', TRUE),
('pain_de_coco_rape_guadeloupean', 'Pain de coco râpé', 315, 5.0, 45.0, 12.5, 3.5, 10.0, 70, 70, 'research', ARRAY['pain de coco râpé', 'pain coco traditionnel', 'coconut roll guadeloupe'], 'traditional', NULL, 1, 'GP', 'Dense coconut bread made with grated dried coconut, giving a richer texture. Sold in small rounds at Guadeloupean patisseries, especially popular in the outer islands of Marie-Galante.', TRUE),
('tourment_damour_guadeloupean', 'Tourment d''amour', 348, 5.5, 52.0, 13.5, 1.5, 28.0, 80, 80, 'research', ARRAY['tourment d''amour', 'tourment d''amour des saintes', 'coconut tart les saintes'], 'traditional', NULL, 1, 'GP', 'Signature pastry from Les Saintes (Terre-de-Haut) islands, consisting of a coconut jam-filled pastry shell. The name translates to ''torment of love'' and it is a prized souvenir from the islands.', TRUE),
('gateau_patate_guadeloupean', 'Gâteau patate', 245, 3.5, 45.0, 6.5, 2.5, 22.0, 100, NULL, 'research', ARRAY['gâteau patate', 'gâteau de patate douce', 'sweet potato cake créole'], 'traditional', NULL, 1, 'GP', 'Sweet potato cake made from mashed sweet potato mixed with coconut, cinnamon, and vanilla. One of the most traditional Guadeloupean dessert pastries, especially popular in rural communities.', TRUE),
('gateau_banane_guadeloupean', 'Gâteau banane', 238, 3.8, 44.0, 6.0, 2.0, 20.0, 100, NULL, 'research', ARRAY['gâteau banane', 'cake à la banane antillais', 'banana bread créole'], 'traditional', NULL, 1, 'GP', 'Banana cake baked with ripe plantain or bananas, spiced with cinnamon and local vanilla. A popular Guadeloupean dessert pastry using the abundant ripe bananas from local plantations.', TRUE),
('gateau_a_la_noix_de_coco_guadeloupean', 'Gâteau à la noix de coco', 390, 5.0, 48.5, 20.0, 4.0, 30.0, 80, NULL, 'research', ARRAY['gâteau à la noix de coco', 'gâteau coco', 'coconut cake antillais'], 'traditional', NULL, 1, 'GP', 'Coconut cake made with freshly grated coconut and coconut milk. A festive Guadeloupean pastry served at celebrations, Carnival, and family gatherings.', TRUE),
('doukounou_guadeloupean', 'Doukounou', 185, 2.5, 35.0, 4.5, 2.8, 12.0, 120, 120, 'research', ARRAY['doukounou', 'dokounou', 'cornmeal banana leaf dumpling'], 'traditional', NULL, 1, 'GP', 'Steamed cornmeal and coconut dumpling wrapped in banana leaves. Doukounou is a West African-origin dish (related to kenkey and dokonu) preserved in Guadeloupe since the era of slavery.', TRUE),
('tablette_coco_guadeloupean', 'Tablette coco', 415, 2.8, 62.0, 18.0, 4.5, 55.0, 30, 30, 'research', ARRAY['tablette coco', 'sucre coco', 'coconut candy tablet'], 'traditional', NULL, 1, 'GP', 'Coconut candy tablet made from grated coconut cooked with brown sugar until hardened. A traditional Guadeloupean confection sold by street vendors, especially during Carnival festivities.', TRUE),
('beignet_de_calalou_guadeloupean', 'Beignet de calalou', 142, 4.5, 18.5, 6.0, 2.8, 1.5, 80, 40, 'research', ARRAY['beignet de calalou', 'beignet feuilles de dachine', 'callaloo fritter'], 'traditional', NULL, 1, 'GP', 'Fritters made from callaloo leaves (taro leaves or amaranth) mixed with seasoned batter. A rustic Guadeloupean snack with deep African culinary roots.', TRUE),
('beignet_de_gombo_guadeloupean', 'Beignet de gombo', 138, 3.5, 17.0, 6.5, 3.0, 1.8, 80, 40, 'research', ARRAY['beignet de gombo', 'okra fritter', 'beignet d''okra'], 'traditional', NULL, 1, 'GP', 'Okra fritters battered and deep fried until golden. Beignets de gombo are a popular street food and appetizer in Guadeloupe, showcasing the African love of okra in the Caribbean.', TRUE),
('beignet_daubergine_guadeloupean', 'Beignet d''aubergine', 132, 2.5, 16.5, 6.5, 2.5, 2.8, 80, 40, 'research', ARRAY['beignet d''aubergine', 'beignet bélangère', 'aubergine fritter'], 'traditional', NULL, 1, 'GP', 'Eggplant fritters seasoned with local spices and herbs. A common side dish and street food in Guadeloupe inspired by both French and African culinary traditions.', TRUE),
('beignet_de_malanga_guadeloupean', 'Beignet de malanga', 155, 3.0, 22.5, 6.0, 2.2, 0.8, 80, 40, 'research', ARRAY['beignet de malanga', 'beignet de tannia', 'malanga fritter'], 'traditional', NULL, 1, 'GP', 'Fritters made from grated malanga (tannia, a type of eddo/taro). Malanga is an Amerindian root vegetable still cultivated in Guadeloupe and used in traditional beignet recipes.', TRUE),
('acras_de_legumes_guadeloupean', 'Acras de légumes', 148, 4.2, 19.0, 6.5, 2.0, 1.5, 80, 25, 'research', ARRAY['acras de légumes', 'acras de légumes créoles', 'vegetable accras'], 'traditional', NULL, 1, 'GP', 'Vegetable fritters (acras) made without fish, using mixed vegetables, herbs, and seasoned batter. A vegetarian version of the classic acras de morue, popular in Guadeloupe.', TRUE),
('acras_de_christophine_guadeloupean', 'Acras de christophine', 140, 3.5, 18.5, 6.0, 1.8, 1.2, 80, 25, 'research', ARRAY['acras de christophine', 'beignets de christophine', 'chayote accras'], 'traditional', NULL, 1, 'GP', 'Christophine fritters made from grated chayote mixed into batter and deep fried. A creative Guadeloupean use of the abundant christophine harvest, served as an appetizer or snack.', TRUE),
('galette_de_mais_guadeloupean', 'Galette de maïs', 210, 4.8, 38.5, 4.5, 3.5, 3.0, 80, 80, 'research', ARRAY['galette de maïs', 'galette de blé d''inde', 'cornmeal cake'], 'traditional', NULL, 1, 'GP', 'Cornmeal flatcake griddled and eaten as bread substitute. Galette de maïs has both French and African influences in Guadeloupean cuisine, eaten with coffee or as a side.', TRUE),
('galette_de_farine_creole_guadeloupean', 'Galette de farine créole', 295, 7.5, 53.0, 6.0, 1.8, 2.5, 80, 80, 'research', ARRAY['galette de farine créole', 'galette créole', 'flour flatbread'], 'traditional', NULL, 1, 'GP', 'Simple flour flatbread cooked on a dry griddle. A rustic everyday bread eaten across Guadeloupe especially in rural areas where traditional oven baking was once impractical.', TRUE),
('dumpling_creole_guadeloupean', 'Dumpling créole', 280, 7.0, 52.0, 4.5, 1.5, 1.0, 80, 80, 'research', ARRAY['dumpling créole', 'boulette de farine', 'flour dumpling créole'], 'traditional', NULL, 1, 'GP', 'Boiled or pan-fried dumplings made from flour and water. Caribbean-style dumplings are eaten alongside soups and stews in Guadeloupe, showing the influence of English-speaking island neighbors.', TRUE),
('pain_de_marie_galante_guadeloupean', 'Pain de Marie-Galante', 268, 8.0, 52.0, 3.2, 2.0, 4.0, 80, NULL, 'research', ARRAY['pain de marie-galante', 'pain artisanal marie-galante', 'wood-fired guadeloupe bread'], 'traditional', NULL, 1, 'GP', 'Traditional bread from Marie-Galante island, baked in wood-fired ovens, with a distinctive crust. The island''s tradition of artisanal bread-making is tied to its sugarcane and rum heritage.', TRUE),
('croissant_guadeloupeen_guadeloupean', 'Croissant guadeloupéen', 406, 8.2, 45.8, 21.0, 2.0, 8.5, 70, 70, 'research', ARRAY['croissant guadeloupéen', 'croissant antillais', 'croissant boulangerie créole'], 'traditional', NULL, 1, 'GP', 'Buttery croissant from Guadeloupean boulangeries, made with local butter. The French pastry tradition is strong in Guadeloupe as an overseas department, with boulangeries on every town square.', TRUE),
('pain_au_chocolat_guadeloupeen_guadeloupean', 'Pain au chocolat guadeloupéen', 392, 7.5, 46.5, 19.5, 2.5, 15.0, 75, 75, 'research', ARRAY['pain au chocolat guadeloupéen', 'chocolatine antillaise', 'chocolate croissant guadeloupe'], 'traditional', NULL, 1, 'GP', 'Flaky pastry filled with dark chocolate, sold in every Guadeloupean boulangerie. The cacao grown on Guadeloupe (especially on Basse-Terre) gives local versions a distinctive terroir.', TRUE),
('chausson_aux_bananes_guadeloupean', 'Chausson aux bananes', 325, 5.0, 48.5, 13.0, 1.8, 18.0, 80, 80, 'research', ARRAY['chausson aux bananes', 'chausson banane antillais', 'banana turnover pastry'], 'traditional', NULL, 1, 'GP', 'Puff pastry turnover filled with cooked banana filling. This banana version of the French chausson aux pommes is a popular Guadeloupean boulangerie pastry substituting local bananas.', TRUE),
('gateau_a_la_papaye_guadeloupean', 'Gâteau à la papaye', 225, 3.5, 42.0, 5.5, 1.8, 22.0, 100, NULL, 'research', ARRAY['gâteau à la papaye', 'cake à la papaye', 'papaya cake créole'], 'traditional', NULL, 1, 'GP', 'Papaya cake using ripe local papaya in the batter. Guadeloupe produces large sweet papayas year-round, and local cooks use them in both sweet and savory preparations.', TRUE),
('gateau_a_la_goyave_guadeloupean', 'Gâteau à la goyave', 238, 3.2, 45.0, 5.8, 2.5, 25.0, 100, NULL, 'research', ARRAY['gâteau à la goyave', 'cake à la goyave antillais', 'guava cake'], 'traditional', NULL, 1, 'GP', 'Guava cake made with guava paste or fresh guava pulp. Goyave (guava) trees grow abundantly across Guadeloupe and the fragrant fruit is prized in jams, pastries, and drinks.', TRUE),
('confiture_de_goyave_guadeloupean', 'Confiture de goyave', 260, 0.5, 65.0, 0.2, 3.0, 62.0, 20, NULL, 'research', ARRAY['confiture de goyave', 'gelée de goyave', 'guava preserve'], 'traditional', NULL, 1, 'GP', 'Guava jam made from locally grown guavas cooked with sugar. Guava preserves are a cottage industry in Guadeloupe and an important product at local markets and craft fairs.', TRUE),
('confiture_de_coco_guadeloupean', 'Confiture de coco', 290, 1.2, 58.0, 7.5, 2.0, 55.0, 20, NULL, 'research', ARRAY['confiture de coco', 'jam coco', 'coconut preserve'], 'traditional', NULL, 1, 'GP', 'Coconut jam made from grated coconut cooked with sugar and spices. Used as a filling in tourment d''amour pastries and spread on bread across Guadeloupe.', TRUE),
('confiture_de_papaye_guadeloupean', 'Confiture de papaye', 245, 0.3, 61.0, 0.1, 1.5, 58.0, 20, NULL, 'research', ARRAY['confiture de papaye', 'gelée de papaye', 'papaya jam'], 'traditional', NULL, 1, 'GP', 'Papaya jam made from green or ripe papaya. Green papaya confiture has a distinctive mild sweetness and is a traditional Guadeloupean preserve spread on pain doux at breakfast.', TRUE),
('fromage_blanc_creole_guadeloupean', 'Fromage blanc créole', 78, 8.5, 5.2, 2.5, 0.0, 5.2, 150, NULL, 'research', ARRAY['fromage blanc créole', 'fromage frais antillais', 'fresh white cheese'], 'traditional', NULL, 1, 'GP', 'Fresh white cheese, a French dairy staple adopted in Guadeloupe as part of its departmental food culture. Eaten with local tropical fruit or honey for breakfast.', TRUE),
('yaourt_a_la_goyave_guadeloupean', 'Yaourt à la goyave', 88, 3.8, 13.5, 2.2, 0.8, 12.0, 125, 125, 'research', ARRAY['yaourt à la goyave', 'yogurt goyave antillais', 'guava yogurt'], 'traditional', NULL, 1, 'GP', 'Guava-flavored yogurt made with local guava pulp. Local dairies in Guadeloupe produce fruit-flavored yogurts using island fruits, a popular breakfast and snack item.', TRUE),
('yaourt_a_la_papaye_guadeloupean', 'Yaourt à la papaye', 82, 3.5, 12.0, 2.2, 0.5, 10.5, 125, 125, 'research', ARRAY['yaourt à la papaye', 'yogurt papaye', 'papaya yogurt antillais'], 'traditional', NULL, 1, 'GP', 'Papaya-flavored yogurt from Guadeloupean dairy producers. Made with locally grown papayas, this yogurt is a popular convenience store and supermarket staple on the island.', TRUE),
('yaourt_a_la_mangue_guadeloupean', 'Yaourt à la mangue', 90, 3.5, 14.5, 2.2, 0.5, 13.0, 125, 125, 'research', ARRAY['yaourt à la mangue', 'yogurt mangue antillais', 'mango yogurt guadeloupe'], 'traditional', NULL, 1, 'GP', 'Mango-flavored yogurt using locally grown Guadeloupean mangoes. Mango season (June-August) is an important cultural moment and the fruit is incorporated into yogurts and desserts.', TRUE),
('lait_de_coco_frais_guadeloupean', 'Lait de coco frais', 230, 2.3, 5.5, 23.8, 2.2, 3.3, 100, NULL, 'research', ARRAY['lait de coco frais', 'lait de noix de coco', 'fresh coconut milk'], 'traditional', NULL, 1, 'GP', 'Freshly extracted coconut milk from mature coconuts. Lait de coco is used extensively in Guadeloupean cuisine for cooking, sauces, desserts, and drinks throughout the island.', TRUE),
('creme_de_coco_guadeloupean', 'Crème de coco', 330, 3.5, 7.2, 34.0, 3.0, 4.5, 60, NULL, 'research', ARRAY['crème de coco', 'coconut cream guadeloupe', 'crème coco épaisse'], 'traditional', NULL, 1, 'GP', 'Thick coconut cream skimmed from the first pressing of coconut milk. Used in rich Guadeloupean sauces, curries, and dessert preparations.', TRUE),
('beurre_creole_aux_epices_guadeloupean', 'Beurre créole aux épices', 698, 1.0, 1.5, 77.0, 0.0, 0.5, 10, NULL, 'research', ARRAY['beurre créole aux épices', 'beurre épicé créole', 'creole compound butter'], 'traditional', NULL, 1, 'GP', 'Compound butter infused with local Creole spices including piment, cives, thyme, and garlic. Used to finish fish and meat dishes in Guadeloupean kitchens.', TRUE),
('ufs_brouilles_aux_cives_guadeloupean', 'Œufs brouillés aux cives', 158, 11.8, 1.5, 11.5, 0.2, 0.8, 120, NULL, 'research', ARRAY['œufs brouillés aux cives', 'omelette aux cives', 'eggs with caribbean chives'], 'traditional', NULL, 1, 'GP', 'Scrambled eggs with cives (Caribbean chives). A simple but iconic Guadeloupean breakfast using locally farmed eggs seasoned with the aromatic local cives herb.', TRUE),
('omelette_creole_au_piment_guadeloupean', 'Omelette créole au piment', 165, 12.0, 2.0, 12.5, 0.3, 1.0, 120, NULL, 'research', ARRAY['omelette créole au piment', 'omelette piment créole', 'creole chili omelette'], 'traditional', NULL, 1, 'GP', 'Creole omelette spiced with piment végétarien and cives. The non-hot local chili pepper (piment végétarien) is a signature flavoring agent used in virtually all Guadeloupean cooking.', TRUE),
('omelette_aux_giraumons_guadeloupean', 'Omelette aux giraumons', 170, 11.5, 5.5, 12.0, 0.5, 2.5, 150, NULL, 'research', ARRAY['omelette aux giraumons', 'omelette au giraumon', 'pumpkin omelette'], 'traditional', NULL, 1, 'GP', 'Omelette filled with sautéed Caribbean pumpkin (giraumon). A creative Guadeloupean egg dish that incorporates the abundant local vegetable harvest.', TRUE),
('omelette_aux_christophines_guadeloupean', 'Omelette aux christophines', 162, 11.0, 5.0, 11.5, 1.2, 1.5, 150, NULL, 'research', ARRAY['omelette aux christophines', 'omelette christophine', 'chayote omelette'], 'traditional', NULL, 1, 'GP', 'Omelette filled with sautéed christophine slices. A Guadeloupean home-cooking staple that pairs eggs with the mild, squash-like christophine for a simple but satisfying meal.', TRUE),
('ufs_mimosa_creoles_guadeloupean', 'Œufs mimosa créoles', 195, 12.5, 3.5, 15.0, 0.3, 1.5, 100, NULL, 'research', ARRAY['œufs mimosa créoles', 'œufs farcis créoles', 'creole deviled eggs'], 'traditional', NULL, 1, 'GP', 'Deviled eggs with a Creole twist, filled with seasoned yolk mixed with chives and piment. The French mimosa egg is adapted with local spices in Guadeloupean buffet tradition.', TRUE),
