('flan_creole_sale_guadeloupean', 'Flan créole salé', 145, 7.5, 10.5, 8.5, 0.5, 4.0, 120, NULL, 'research', ARRAY['flan créole salé', 'flan de légumes créole', 'savory custard antillais'], 'traditional', NULL, 1, 'GP', 'Savory egg custard flan with local vegetables and herbs. Adapted from the French flan salé tradition with local Guadeloupean ingredients and creole seasoning.', TRUE),
('gratin_dufs_creole_guadeloupean', 'Gratin d''œufs créole', 198, 12.0, 8.5, 13.0, 0.8, 3.5, 150, NULL, 'research', ARRAY['gratin d''œufs créole', 'œufs au gratin créoles', 'egg gratin antillais'], 'traditional', NULL, 1, 'GP', 'Baked egg gratin with vegetables and cheese. A Guadeloupean adaptation of the French egg gratin, enriched with local vegetables and béchamel seasoned with local spices.', TRUE),
('madere_saute_guadeloupean', 'Madère sauté', 98, 1.5, 22.5, 0.5, 3.2, 3.5, 150, NULL, 'research', ARRAY['madère sauté', 'tannia sauté', 'malanga sauté créole'], 'traditional', NULL, 1, 'GP', 'Sautéed madère (Xanthosoma sagittifolium), a tannia variety, with garlic and thyme. Madère is a starchy root closely related to malanga, cultivated throughout Guadeloupe.', TRUE),
('citrouille_sautee_epicee_guadeloupean', 'Citrouille sautée épicée', 35, 1.0, 8.0, 0.8, 0.8, 3.5, 150, NULL, 'research', ARRAY['citrouille sautée épicée', 'courge sautée épicée', 'spiced squash sauté'], 'traditional', NULL, 1, 'GP', 'Spicy sautéed calabash squash with piment végétarien and herbs. Citrouille is used interchangeably with giraumon in Guadeloupean cooking and is a versatile seasonal vegetable.', TRUE),
('ratatouille_creole_guadeloupean', 'Ratatouille créole', 52, 1.8, 8.5, 2.2, 3.0, 5.0, 200, NULL, 'research', ARRAY['ratatouille créole', 'ratatouille antillaise', 'creole vegetable stew'], 'traditional', NULL, 1, 'GP', 'Creole version of ratatouille using local vegetables: christophine, eggplant, giraumon, and tomatoes with Creole spices. A fusion of French and local Guadeloupean culinary traditions.', TRUE),
('gratin_de_patate_douce_guadeloupean', 'Gratin de patate douce', 175, 4.5, 28.5, 5.5, 3.0, 8.5, 180, NULL, 'research', ARRAY['gratin de patate douce', 'patate douce au gratin', 'sweet potato gratin antillais'], 'traditional', NULL, 1, 'GP', 'Sweet potato gratin baked with cheese and cream. Local sweet potato varieties (batata) from Guadeloupe are shorter and more orange than European types, richer in flavor.', TRUE),
