('gratin_de_manioc_guadeloupean', 'Gratin de manioc', 195, 5.0, 32.5, 6.0, 2.0, 2.0, 180, NULL, 'research', ARRAY['gratin de manioc', 'manioc au gratin', 'cassava gratin'], 'traditional', NULL, 1, 'GP', 'Cassava gratin baked with béchamel and cheese. This dish merges the Amerindian cassava tradition with French gratin cooking, creating a uniquely Guadeloupean fusion side dish.', TRUE),
('riz_creole_aux_haricots_guadeloupean', 'Riz créole aux haricots', 155, 5.5, 30.5, 1.5, 3.2, 0.8, 200, NULL, 'research', ARRAY['riz créole aux haricots', 'riz et pois rouges', 'rice and red beans créole'], 'traditional', NULL, 1, 'GP', 'Classic Guadeloupean rice and beans dish (riz et pois rouges). One of the most fundamental combinations in Creole cuisine, eaten daily across the island as a main carbohydrate side.', TRUE),
