('riz_colombo_guadeloupean', 'Riz colombo', 165, 4.0, 32.0, 2.8, 1.5, 1.0, 180, NULL, 'research', ARRAY['riz colombo', 'riz au colombo', 'colombo-spiced rice'], 'traditional', NULL, 1, 'GP', 'Rice flavored with colombo spice blend, the Guadeloupean curry powder introduced by Indian indentured workers after 1848. Colombo seasoning is a defining flavor of modern Guadeloupean cuisine.', TRUE),
('gratin_de_riz_creole_guadeloupean', 'Gratin de riz créole', 185, 6.5, 28.5, 6.0, 0.8, 2.5, 200, NULL, 'research', ARRAY['gratin de riz créole', 'gratin de riz antillais', 'baked rice gratin'], 'traditional', NULL, 1, 'GP', 'Baked rice gratin with cheese and cream, a French technique applied to the rice that forms the basis of the Guadeloupean diet. Popular in school canteens and family restaurants.', TRUE),
('semoule_creole_guadeloupean', 'Semoule créole', 150, 5.0, 31.0, 0.8, 1.8, 1.5, 180, NULL, 'research', ARRAY['semoule créole', 'couscous créole', 'semolina side dish'], 'traditional', NULL, 1, 'GP', 'Couscous semolina cooked and served as a side starch, a French colonial influence in Guadeloupean cuisine. Often prepared with butter and local herbs as a rice alternative.', TRUE),
('puree_de_patate_douce_guadeloupean', 'Purée de patate douce', 96, 2.0, 21.5, 1.0, 3.2, 7.5, 180, NULL, 'research', ARRAY['purée de patate douce', 'purée de batata', 'sweet potato mash créole'], 'traditional', NULL, 1, 'GP', 'Smooth sweet potato purée with butter and a hint of nutmeg or cinnamon. Patate douce (sweet potato) purée is a beloved Guadeloupean side dish especially for festive occasions.', TRUE),
('puree_de_pois_casses_guadeloupean', 'Purée de pois cassés', 118, 8.5, 21.0, 0.5, 8.0, 2.0, 180, NULL, 'research', ARRAY['purée de pois cassés', 'purée pois cassés créole', 'split pea mash'], 'traditional', NULL, 1, 'GP', 'Split pea purée cooked with garlic, thyme, and cives. A thick and hearty side dish eaten across Guadeloupe, influenced by both French cuisine and the local legume tradition.', TRUE),
('feculents_creoles_au_coco_guadeloupean', 'Féculents créoles au coco', 198, 3.5, 35.0, 5.5, 4.0, 4.5, 200, NULL, 'research', ARRAY['féculents créoles au coco', 'légumes racines au coco', 'roots in coconut milk'], 'traditional', NULL, 1, 'GP', 'Mixed starchy roots (igname, dachine, patate douce) cooked in coconut milk. A comforting one-pot side dish celebrating the variety of local roots cultivated across Guadeloupe.', TRUE),
('pain_de_mie_creole_guadeloupean', 'Pain de mie créole', 275, 8.0, 50.5, 4.5, 2.0, 5.0, 60, NULL, 'research', ARRAY['pain de mie créole', 'pain de mie antillais', 'soft white bread guadeloupe'], 'traditional', NULL, 1, 'GP', 'Soft sandwich bread from Guadeloupean bakeries, adapted from French pain de mie. Used for sandwiches and toast across the island and sold in every supermarché.', TRUE),
('pain_complet_guadeloupeen_guadeloupean', 'Pain complet guadeloupéen', 248, 9.5, 45.0, 3.5, 6.5, 3.5, 60, NULL, 'research', ARRAY['pain complet guadeloupéen', 'pain aux céréales antillais', 'whole wheat bread guadeloupe'], 'traditional', NULL, 1, 'GP', 'Whole wheat bread baked in local boulangeries. As health consciousness has grown in Guadeloupe, whole grain breads have become popular alongside traditional white breads.', TRUE),
('pain_aux_raisins_guadeloupeen_guadeloupean', 'Pain aux raisins guadeloupéen', 332, 7.5, 55.0, 10.0, 2.0, 18.0, 70, 70, 'research', ARRAY['pain aux raisins guadeloupéen', 'escargot aux raisins', 'raisin roll antillais'], 'traditional', NULL, 1, 'GP', 'Raisin-filled sweet pastry roll from Guadeloupean boulangeries. A morning pastry staple combining French technique with tropical flavors, often eaten with café or chocolat chaud.', TRUE),
('choux_a_la_creme_creole_guadeloupean', 'Choux à la crème créole', 310, 6.5, 30.0, 18.5, 0.5, 14.0, 70, 70, 'research', ARRAY['choux à la crème créole', 'profiterole créole', 'cream puff antillais'], 'traditional', NULL, 1, 'GP', 'Cream puffs filled with local vanilla or coconut cream. The French choux pastry tradition is well-established in Guadeloupe''s boulangerie-pâtisseries, sold in all town centers.', TRUE),
('eclair_guadeloupeen_guadeloupean', 'Éclair guadeloupéen', 295, 6.0, 32.5, 16.0, 0.5, 16.0, 75, 75, 'research', ARRAY['éclair guadeloupéen', 'éclair passion', 'éclair coco antillais'], 'traditional', NULL, 1, 'GP', 'Classic French éclair adapted in Guadeloupe with local flavors such as passion fruit glaze or coconut cream filling. A sophisticated pastry sold in island pâtisseries.', TRUE),
('mille_feuille_creole_guadeloupean', 'Mille-feuille créole', 398, 5.5, 45.0, 22.0, 0.8, 22.0, 90, 90, 'research', ARRAY['mille-feuille créole', 'millefeuille antillais', 'napoleon créole'], 'traditional', NULL, 1, 'GP', 'Layered puff pastry with cream filling, a French pastry mainstay adopted in Guadeloupean pâtisseries. Local versions sometimes use passion fruit or coconut in the crème pâtissière.', TRUE),
('tarte_aux_fruits_tropicaux_guadeloupean', 'Tarte aux fruits tropicaux', 285, 4.5, 38.5, 13.0, 1.5, 20.0, 100, NULL, 'research', ARRAY['tarte aux fruits tropicaux', 'tarte tropicale', 'tropical fruit tart'], 'traditional', NULL, 1, 'GP', 'Open-faced pastry tart topped with local tropical fruits like mango, pineapple, and passion fruit on crème pâtissière. A showpiece of Guadeloupe''s French pâtisserie tradition.', TRUE),
('tarte_a_la_goyave_guadeloupean', 'Tarte à la goyave', 275, 4.0, 40.0, 11.5, 2.0, 22.0, 100, NULL, 'research', ARRAY['tarte à la goyave', 'tarte goyave créole', 'guava tart'], 'traditional', NULL, 1, 'GP', 'Guava tart in a shortcrust pastry shell. Guava jam or fresh guava is used to fill pastry tarts in Guadeloupean pâtisseries, combining French technique with local fruit.', TRUE),
('galette_des_rois_creole_guadeloupean', 'Galette des Rois créole', 385, 6.5, 42.0, 22.0, 1.5, 15.0, 100, NULL, 'research', ARRAY['galette des rois créole', 'galette des rois antillaise', 'epiphany cake guadeloupe'], 'traditional', NULL, 1, 'GP', 'King cake eaten at Epiphany in January, a French tradition deeply embedded in Guadeloupean culture. Local versions sometimes incorporate coconut or tropical fruit in the frangipane filling.', TRUE),
('buche_de_noel_creole_guadeloupean', 'Bûche de Noël créole', 358, 5.5, 40.0, 20.0, 1.0, 28.0, 100, NULL, 'research', ARRAY['bûche de noël créole', 'bûche de noël antillaise', 'christmas log guadeloupe'], 'traditional', NULL, 1, 'GP', 'Christmas yule log cake, a mandatory part of Guadeloupean Christmas celebrations. Local versions incorporate rum, coconut, and tropical fruit flavors into the rolled sponge and buttercream.', TRUE),
('macaron_coco_guadeloupean', 'Macaron coco', 425, 4.5, 58.0, 20.0, 3.5, 48.0, 30, 30, 'research', ARRAY['macaron coco', 'macaron à la noix de coco', 'coconut macaroon créole'], 'traditional', NULL, 1, 'GP', 'Coconut macaroon cookie made with freshly grated coconut, egg white, and sugar. A popular Guadeloupean confection sold by street vendors and in local pâtisseries.', TRUE),
('rocher_coco_guadeloupean', 'Rocher coco', 440, 4.0, 55.0, 23.0, 4.5, 45.0, 25, 25, 'research', ARRAY['rocher coco', 'coconut rock candy', 'rocher noix de coco'], 'traditional', NULL, 1, 'GP', 'Small mounded coconut confection with a crispy exterior. Rochers coco are a traditional Guadeloupean sweet sold at school gates and market stalls across the island.', TRUE),
('bonbon_coco_guadeloupean', 'Bonbon coco', 418, 2.5, 60.0, 20.0, 3.8, 52.0, 25, 25, 'research', ARRAY['bonbon coco', 'coconut candy créole', 'bonbon noix de coco'], 'traditional', NULL, 1, 'GP', 'Traditional coconut candy in Guadeloupe, made by boiling grated coconut with sugar and spices until it sets. A childhood favorite and a symbol of Creole confectionery heritage.', TRUE),
('sukari_canne_guadeloupean', 'Sukari canne', 312, 0.0, 80.0, 0.0, 0.0, 80.0, 20, NULL, 'research', ARRAY['sukari canne', 'canne à sucre caramélisée', 'sugarcane sweet'], 'traditional', NULL, 1, 'GP', 'Raw sugarcane juice reduced to crystallized candy. Guadeloupe''s centuries-long sugarcane industry (established under French colonialism) produced this simple confection from cane syrup.', TRUE),
('sirop_de_canne_guadeloupean', 'Sirop de canne', 280, 0.0, 72.0, 0.0, 0.0, 70.0, 30, NULL, 'research', ARRAY['sirop de canne', 'cane syrup guadeloupe', 'mélasse légère'], 'traditional', NULL, 1, 'GP', 'Pure sugarcane syrup, a byproduct of Guadeloupe''s sugar industry. Used to sweeten drinks, desserts, and confections; the flavor is far richer and more complex than refined sugar.', TRUE),
('banane_flambee_guadeloupean', 'Banane flambée', 195, 1.2, 38.0, 4.5, 2.2, 25.0, 150, NULL, 'research', ARRAY['banane flambée', 'banane au rhum flambée', 'flambéed banana créole'], 'traditional', NULL, 1, 'GP', 'Ripe banana flambéed with local rum and brown sugar. A classic Guadeloupean restaurant dessert that showcases both the island''s banana harvest and its famous rum production.', TRUE),
('gratin_de_bananes_au_rhum_guadeloupean', 'Gratin de bananes au rhum', 242, 3.5, 40.0, 8.5, 2.0, 22.0, 180, NULL, 'research', ARRAY['gratin de bananes au rhum', 'banane au four rhum', 'rum banana gratin'], 'traditional', NULL, 1, 'GP', 'Baked banana gratin glazed with rum and cream. A rich Guadeloupean dessert combining the island''s two great agricultural products: bananas and sugarcane rum.', TRUE),
('blanc_manger_coco_guadeloupean', 'Blanc-manger coco', 185, 2.5, 25.0, 9.0, 1.5, 20.0, 150, NULL, 'research', ARRAY['blanc-manger coco', 'blanc manger créole', 'coconut blancmange'], 'traditional', NULL, 1, 'GP', 'Set coconut milk pudding made with coconut milk, sugar, and a gelling agent. Blanc-manger coco is one of the most beloved Guadeloupean desserts, served chilled at family celebrations.', TRUE),
('pouding_creole_guadeloupean', 'Pouding créole', 265, 5.5, 42.0, 9.0, 0.8, 28.0, 150, NULL, 'research', ARRAY['pouding créole', 'bread pudding antillais', 'pouding au rhum'], 'traditional', NULL, 1, 'GP', 'Baked bread pudding with rum, raisins, and vanilla. Pouding créole is a thrifty dessert made from stale bread soaked in egg custard, popular in traditional Guadeloupean households.', TRUE),
('flan_coco_guadeloupean', 'Flan coco', 218, 4.5, 30.0, 9.5, 0.8, 26.0, 120, NULL, 'research', ARRAY['flan coco', 'crème caramel coco', 'coconut flan'], 'traditional', NULL, 1, 'GP', 'Coconut caramel flan (crème caramel) made with coconut milk. A staple dessert in Guadeloupean restaurants and homes, combining the French crème caramel with local coconut.', TRUE),
('beignet_de_carnaval_guadeloupean', 'Beignet de carnaval', 325, 6.0, 48.0, 13.0, 1.5, 12.0, 80, 40, 'research', ARRAY['beignet de carnaval', 'beignets de mardi gras', 'carnival fritters guadeloupe'], 'traditional', NULL, 1, 'GP', 'Sweet doughnuts made and sold during Guadeloupe''s Carnival season (January-February). These fried dough balls are dusted with powdered sugar and are a festive street food tradition.', TRUE),
