('sorbet_coco_maison_guadeloupean', 'Sorbet coco maison', 178, 1.8, 28.0, 7.5, 1.5, 24.0, 120, NULL, 'research', ARRAY['sorbet coco maison', 'sorbet coco artisanal', 'coconut sorbet créole'], 'traditional', NULL, 1, 'GP', 'Handmade coconut sorbet traditionally churned in a wooden tub with ice and salt. Sorbets crafted by street vendors are a beloved part of Guadeloupean food culture.', TRUE),
('sorbet_goyave_guadeloupean', 'Sorbet goyave', 125, 0.8, 32.0, 0.2, 2.0, 28.0, 120, NULL, 'research', ARRAY['sorbet goyave', 'sorbet goyave maison', 'guava sorbet artisanal'], 'traditional', NULL, 1, 'GP', 'Guava sorbet made from fresh local guava pulp. Sold by sorbet vendors (called sorbetiers) at beaches and markets throughout Guadeloupe using traditional hand-cranked churns.', TRUE),
('sorbet_maracudja_guadeloupean', 'Sorbet maracudja', 118, 0.8, 30.0, 0.2, 2.5, 26.0, 120, NULL, 'research', ARRAY['sorbet maracudja', 'sorbet passion', 'passion fruit sorbet créole'], 'traditional', NULL, 1, 'GP', 'Passion fruit sorbet with intense tart-sweet flavor. Maracudja (passion fruit) is one of the most popular flavors for Guadeloupean sorbets and drinks.', TRUE),
('yaourt_nature_antillais_guadeloupean', 'Yaourt nature antillais', 61, 3.5, 4.7, 3.3, 0.0, 4.7, 125, 125, 'research', ARRAY['yaourt nature antillais', 'yaourt nature créole', 'plain yogurt guadeloupe'], 'traditional', NULL, 1, 'GP', 'Plain whole milk yogurt from Guadeloupean dairy producers. Local dairies on the island produce artisanal yogurts using milk from local farms, eaten with tropical fruit preserves.', TRUE),
