('fromage_de_lile_guadeloupean', 'Fromage de l''île', 295, 18.5, 1.5, 23.5, 0.0, 0.5, 50, NULL, 'research', ARRAY['fromage de l''île', 'fromage local antillais', 'island fresh cheese'], 'traditional', NULL, 1, 'GP', 'Fresh semi-soft artisanal cheese made on Guadeloupe from local milk. Small-scale cheese production exists on the island blending French cheesemaking traditions with local dairy.', TRUE),
('lait_chaud_a_la_cannelle_guadeloupean', 'Lait chaud à la cannelle', 72, 3.4, 10.5, 1.8, 0.2, 9.5, 200, NULL, 'research', ARRAY['lait chaud à la cannelle', 'lait chaud cannelle créole', 'cinnamon milk antillais'], 'traditional', NULL, 1, 'GP', 'Warm spiced milk with cinnamon, a traditional Guadeloupean bedtime and morning drink for children. Cinnamon (cannelle pays) from local trees has a more complex flavor than Ceylon cinnamon.', TRUE),
('chocolat_chaud_creole_guadeloupean', 'Chocolat chaud créole', 112, 4.5, 16.5, 4.0, 1.5, 12.0, 200, NULL, 'research', ARRAY['chocolat chaud créole', 'chocolat cacao pays', 'local cacao hot drink'], 'traditional', NULL, 1, 'GP', 'Hot chocolate made with locally grown cacao. Basse-Terre has a tradition of cacao cultivation and artisanal chocolate production, with chocolate drinks made from pure cacao paste.', TRUE),
