('pate_de_cacao_pays_guadeloupean', 'Pâte de cacao pays', 228, 6.0, 25.0, 12.5, 4.5, 18.0, 40, 40, 'research', ARRAY['pâte de cacao pays', 'tablette cacao pays', 'cacao paste disk guadeloupe'], 'traditional', NULL, 1, 'GP', 'Raw cacao paste disk used to make traditional chocolate drinks and desserts. Guadeloupean cacao paste (tablette de chocolat pays) is grated into hot water or milk to make the traditional morning drink.', TRUE),
('creme_patissiere_a_la_vanille_pays_guadeloupean', 'Crème pâtissière à la vanille pays', 185, 4.5, 26.5, 7.0, 0.0, 18.0, 100, NULL, 'research', ARRAY['crème pâtissière à la vanille pays', 'crème pâtissière créole', 'vanilla pastry cream'], 'traditional', NULL, 1, 'GP', 'Classic pastry cream made with local Guadeloupean vanilla beans. Used in éclairs, tarts, and cream puffs in island pâtisseries; the local vanilla adds a floral complexity.', TRUE),
