('mousse_au_chocolat_pays_guadeloupean', 'Mousse au chocolat pays', 298, 6.5, 22.0, 21.0, 2.0, 18.0, 120, NULL, 'research', ARRAY['mousse au chocolat pays', 'mousse cacao pays', 'local chocolate mousse'], 'traditional', NULL, 1, 'GP', 'Chocolate mousse made with local Guadeloupe cacao. A French dessert elevated with fine local chocolate from Basse-Terre cacao farms, served in Guadeloupean restaurants.', TRUE),
