('salade_de_corossol_guadeloupean', 'Salade de corossol', 55, 0.9, 14.0, 0.2, 3.0, 11.0, 120, NULL, 'research', ARRAY['salade de corossol', 'salade corossole', 'soursop salad'], 'traditional', NULL, 1, 'GP', 'Soursop (corossol/corossole) fruit salad with lime and mint. Soursop grows wild across Basse-Terre and is used in salads, drinks, and ice creams throughout Guadeloupe.', TRUE),
