('salade_de_soja_creole_guadeloupean', 'Salade de soja créole', 58, 5.8, 4.2, 2.5, 2.0, 1.5, 120, NULL, 'research', ARRAY['salade de soja créole', 'salade germes soja', 'bean sprout salad créole'], 'traditional', NULL, 1, 'GP', 'Bean sprout and soybean salad with local herbs and lime dressing. The Chinese-Caribbean community (descendants of 19th-century contract workers) introduced soybean dishes to Guadeloupe.', TRUE),
